const raw  = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;

if (!body.job_id)                           throw new Error('Stage 2 missing: job_id');
if (!body.image_prompt && !body.image_url)  throw new Error('Stage 2 missing: image_prompt (or pre-provide image_url to skip Seedream)');
if (!body.quote)                            throw new Error('Stage 2 missing: quote');

const wsKey = $env.WAVESPEED_API_KEY || '';
if (!wsKey) console.warn('WARNING: WAVESPEED_API_KEY not set — Seedream call will fail');

console.log('Stage 2 START | job:', body.job_id, '| philosopher:', body.philosopher);

return [{ json: { ...body, ws_key: wsKey } }];

const https = require('https');
const data  = $input.first().json;

// If image_url is already provided, skip Seedream entirely (useful for retests)
if (data.image_url) {
  console.log('image_url pre-provided, skipping Seedream API call:', data.image_url);
  return [{ json: { ...data, seedream_job_id: null, poll_attempt: 0, all_done: 1 } }];
}

const wsKey = data.ws_key || $env.WAVESPEED_API_KEY;
const prompt = data.image_prompt;

if (!wsKey) throw new Error('WAVESPEED_API_KEY not set. Add in n8n Settings > Environment Variables.');
if (!prompt) throw new Error('Missing image_prompt going into Seedream submission.');

const body = { prompt, size: '1024*1024', seed: -1, enable_base64_output: false, enable_sync_mode: false };
const buf = Buffer.from(JSON.stringify(body));

const result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.wavespeed.ai',
    path:     '/api/v3/bytedance/seedream-v4',
    method:   'POST',
    headers:  { 'Authorization': 'Bearer ' + wsKey, 'Content-Type': 'application/json', 'Content-Length': buf.length }
  }, (res) => {
    const chunks = [];
    res.on('data', c => chunks.push(c));
    res.on('end', () => {
      try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
      catch(e) { reject(new Error('Bad JSON from Wavespeed: ' + Buffer.concat(chunks).toString().slice(0,300))); }
    });
  });
  req.on('error', reject);
  req.write(buf);
  req.end();
});

if (!result.data || !result.data.id) throw new Error('Seedream submit failed: ' + JSON.stringify(result).slice(0,300));
console.log('Seedream submitted -> ' + result.data.id);

return [{ json: { ...data, seedream_job_id: result.data.id, image_url: null, poll_attempt: 0, all_done: 0, submitted_at: Date.now() } }];

const https  = require('https');
const data   = $input.first().json;

// If image was pre-provided (bypass mode), skip polling entirely
if (data.all_done == 1 && !data.seedream_job_id) {
  console.log('Image pre-provided, skipping Seedream poll');
  return [{ json: { ...data, all_done: 1 } }];
}

const wsKey  = data.ws_key || $env.WAVESPEED_API_KEY;
const jobId  = data.seedream_job_id;
const attempt= (data.poll_attempt || 0) + 1;

if (!wsKey) throw new Error('WAVESPEED_API_KEY not set.');
console.log('--- Poll #' + attempt + ' (image) ---');

function apiGet(taskId) {
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path:     '/api/v3/predictions/' + taskId + '/result',
      method:   'GET',
      headers:  { 'Authorization': 'Bearer ' + wsKey }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => { try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch(e) { reject(new Error('Non-JSON from Wavespeed')); } });
    });
    req.on('error', reject);
    req.end();
  });
}

const r = await apiGet(jobId);
const status = (r.data && r.data.status) || 'unknown';
const pct    = r.data && r.data.progress != null ? ' (' + r.data.progress + '%)' : '';
console.log('Image -> ' + status + pct);

let imageUrl = data.image_url;
let all_done = 0;
if (status === 'completed') {
  imageUrl = r.data.outputs && r.data.outputs[0];
  if (!imageUrl) throw new Error('Image completed but no output URL: ' + JSON.stringify(r.data).slice(0,300));
  all_done = 1;
  console.log('Image ready: ' + imageUrl.split('?')[0].slice(-40));
} else if (status === 'failed') {
  throw new Error('Seedream image FAILED: ' + JSON.stringify(r.data));
}

return [{ json: { ...data, image_url: imageUrl, poll_attempt: attempt, all_done } }];

const { execSync } = require('child_process');
const fs = require('fs');
const data  = $input.first().json;
const jobId = data.job_id;
const url   = data.image_url;

if (!url) throw new Error('Missing image_url going into download');

const n8nPath  = '/data/manim/renders/' + jobId + '_seedream.png';
const contPath = '/ffmpeg/manim_renders/' + jobId + '_seedream.png';

// file:// means the image is already on the shared volume — skip curl (which would truncate the file)
if (url.startsWith('file://')) {
  if (!fs.existsSync(n8nPath)) throw new Error('Pre-provided file not found: ' + n8nPath);
  console.log('file:// bypass — existing file at ' + n8nPath + ' (' + fs.statSync(n8nPath).size + ' bytes)');
} else {
  console.log('Downloading Seedream image: ' + url.split('?')[0].slice(-60));
  const cmd = 'docker exec phys_ffmpeg_runner curl -sL -o "' + contPath + '" "' + url + '" && echo DL_OK';
  const res = execSync(cmd, { encoding: 'utf-8', timeout: 60000 });
  if (!res.includes('DL_OK')) throw new Error('Image download failed: ' + res.slice(-300));
  if (!fs.existsSync(n8nPath)) throw new Error('File missing after download: ' + n8nPath);
}

console.log('Saved: ' + n8nPath);
return [{ json: { ...data, seedream_image_path: n8nPath } }];

const data = $input.first().json;
if (!data.job_id)              throw new Error('Missing job_id going into assembly');
if (!data.seedream_image_path) throw new Error('Missing seedream_image_path going into assembly');
if (!data.quote)               throw new Error('Missing quote going into assembly');
return [{ json: {
  job_id:              data.job_id,
  philosopher:         data.philosopher || 'Unknown',
  attribution:         data.attribution || data.philosopher || 'Unknown',
  era:                 data.era || 'historical',
  quote:               data.quote,
  caption:             data.caption || '',
  title:               data.title || data.philosopher,
  hashtags:             data.hashtags || '#philosophy #psychology #aperture',
  seedream_image_path: data.seedream_image_path,
  bgm_path:            data.bgm_path || null,
  sheet_row:           data.sheet_row || null,
  start_time:          data.start_time || Date.now()
}}];

const { spawnSync, execSync } = require('child_process');
const data  = $input.first().json;
const jobId = data.job_id;

const config = JSON.stringify({
  bg_path:     '/manim/renders/' + jobId + '_seedream.png',
  output_path: '/manim/renders/' + jobId + '_quote.mp4',
  quote:       data.quote,
  attribution: data.attribution,
  video_dur:   15,
  fps:         30
});

const tmpCfg = '/tmp/apr_cfg_' + Date.now() + '.json';
const write = spawnSync('docker', ['exec', '-i', 'qpc_manim_runner', 'bash', '-c', 'cat > ' + tmpCfg],
  { input: config, encoding: 'utf-8', timeout: 10000 });
if (write.status !== 0) throw new Error('Failed to write compositor config: ' + (write.stderr || ''));

let stdout;
try {
  stdout = execSync(
    'docker exec qpc_manim_runner python3 /manim/scripts/composite_aperture_quote.py ' + tmpCfg,
    { encoding: 'utf-8', timeout: 300000 }
  );
} catch (e) {
  throw new Error('Compositor failed: ' + ((e.stdout || '') + (e.stderr || '') || e.message).slice(0, 1000));
}

try { execSync('docker exec qpc_manim_runner rm -f ' + tmpCfg, { timeout: 5000 }); } catch(_) {}

if (!stdout.includes('OK:')) throw new Error('Compositor did not confirm OK:\n' + stdout.slice(-500));

console.log('Compositor output:\n' + stdout.trim());
return [{ json: { ...data, quote_video_path: '/data/manim/renders/' + jobId + '_quote.mp4' } }];

const { execSync } = require('child_process');
const fs = require('fs');

const data  = $input.first().json;
const jobId = data.job_id;
const VIDEO_DUR = 15;
const FPS = 30;
const FADE_DUR = 1.0;

const n8nOut  = '/data/ffmpeg/output';
const contOut = '/ffmpeg/output';
if (!fs.existsSync(n8nOut)) fs.mkdirSync(n8nOut, { recursive: true });

function run(cmd, ms) {
  ms = ms || 120000;
  console.log('CMD: ' + cmd.slice(0, 220));
  let out = '';
  try { out = execSync(cmd, { encoding: 'utf-8', timeout: ms }); }
  catch(e) { out = (e.stdout||'') + (e.stderr||''); }
  return out.toString();
}

const imgFile = '/ffmpeg/manim_renders/' + jobId + '_quote.mp4';
const hasImg = run('docker exec phys_ffmpeg_runner test -f "' + imgFile + '" && echo OK').includes('OK');
if (!hasImg) throw new Error('Compositor video missing at ' + imgFile);

let bgmFile = data.bgm_path ? data.bgm_path.replace('/data/ffmpeg', '/ffmpeg') : null;
const hasBgm = !!(bgmFile && run('docker exec phys_ffmpeg_runner test -f "' + bgmFile + '" && echo OK').includes('OK'));
console.log('Assets | image:' + hasImg + ' | bgm:' + hasBgm);

// Static image (no zoom/pan — zoompan was causing visible shake/tilt), just a
// clean fade in from black at the start and fade out to black at the end.
const vf =
  "[0:v]fade=t=in:st=0:d=" + FADE_DUR + ",fade=t=out:st=" + (VIDEO_DUR - FADE_DUR) + ":d=" + FADE_DUR + "[outv]";

const inp = ['-i "' + imgFile + '"'];
let amap = '-an';
let afull = '';

if (hasBgm) {
  inp.push('-i "' + bgmFile + '"');
  afull = ";[1:a]atrim=0:" + VIDEO_DUR + ",afade=t=in:st=0:d=" + FADE_DUR + ",afade=t=out:st=" + (VIDEO_DUR - FADE_DUR) + ":d=" + FADE_DUR + "[aout]";
  amap = '-map "[aout]" -c:a aac -b:a 192k';
}

const fullFilter = vf + afull;

const cmd =
  'docker exec phys_ffmpeg_runner ffmpeg -y ' + inp.join(' ') +
  ' -filter_complex "' + fullFilter + '" -map "[outv]" ' + amap +
  ' -c:v libx264 -crf 18 -preset fast -pix_fmt yuv420p -movflags +faststart' +
  ' -t ' + VIDEO_DUR + ' "' + contOut + '/' + jobId + '_final.mp4" && echo FINAL_OK';

const result = run(cmd, 300000);
if (!result.includes('FINAL_OK')) throw new Error('Final render failed:\n' + result.slice(-800));

const finalPath = n8nOut + '/' + jobId + '_final.mp4';
if (!fs.existsSync(finalPath)) throw new Error('Output not on disk: ' + finalPath);

const elapsed = Math.round((Date.now() - data.start_time) / 1000);
console.log('Assembly complete | ' + jobId + ' | ' + elapsed + 's | ' + finalPath);

// Extract thumbnail at 5s
const thumbFilename = jobId + '_thumb.jpg';
const thumbPathN8n = n8nOut + '/' + thumbFilename;
const thumbPathCont = contOut + '/' + thumbFilename;
const thumbResult = run('docker exec phys_ffmpeg_runner ffmpeg -y -ss 5 -i "' + contOut + '/' + jobId + '_final.mp4" -vframes 1 -q:v 2 "' + thumbPathCont + '" 2>&1 && echo THUMB_OK', 30000);
const thumbOk = thumbResult.includes('THUMB_OK');
console.log('Thumb:', thumbOk ? 'OK at ' + thumbPathN8n : 'FAILED: ' + thumbResult.slice(-150));
return [{ json: { ...data, final_video_path: finalPath, output_filename: jobId + '_final.mp4', assembly_time_sec: elapsed, thumb_path: thumbOk ? thumbPathN8n : null, thumb_filename: thumbFilename } }];

const fs = require('fs');
const data = $input.first().json;
const filePath = data.final_video_path;
if (!fs.existsSync(filePath)) throw new Error('Final video missing: ' + filePath);
const destDir = '/root/.n8n-files';
if (!fs.existsSync(destDir)) fs.mkdirSync(destDir, { recursive: true });
const destPath = destDir + '/' + data.output_filename;
fs.copyFileSync(filePath, destPath);
console.log('Copied final video into n8n-allowed path: ' + destPath);
return [{ json: { ...data, n8n_file_path: destPath } }];

const videoUpload = $('Upload to Google Drive').first().json;
const assembleData = $('Assemble Video').first().json;

// Thumb URL (optional)
let thumbUrl = null;
try {
  const thumbUpload = $('Upload Thumbnail to Drive').first().json;
  if (thumbUpload && thumbUpload.id) {
    thumbUrl = 'https://drive.google.com/uc?export=download&id=' + thumbUpload.id;
  }
} catch(e) { console.log('No thumb upload data:', e.message); }

const fileId = videoUpload.id;
const videoUrl = 'https://drive.google.com/uc?export=download&id=' + fileId;
const renderTimeSec = Math.round((Date.now() - assembleData.start_time) / 1000);

return [{ json: {
  job_id:              assembleData.job_id,
  topic:               assembleData.topic,
  title:               assembleData.title,
  quote:               assembleData.quote || '',
  caption:             assembleData.caption || '',
  hashtags:            assembleData.hashtags || '',
  philosopher:         assembleData.philosopher || '',
  video_url:           videoUrl,
  drive_file_id:       fileId,
  drive_video_url:     videoUrl,
  thumb_url:           thumbUrl,
  render_time_seconds: renderTimeSec,
  sheet_row:           assembleData.sheet_row,
  status:              'stage2_complete'
} }];

const data = $input.first().json;
const totalSec = Math.round((Date.now() - (data.start_time||Date.now())) / 1000);
console.log('=== APERTURE STAGE 2 COMPLETE (quote image gen + assembly + drive) ===');
console.log('Job:         ' + data.job_id);
console.log('Philosopher: ' + data.philosopher);
console.log('Quote:       ' + (data.quote||'').slice(0,60));
console.log('File:        ' + data.final_video_path);
console.log('Drive:       ' + (data.drive_file_id || 'not uploaded'));
console.log('Time:        ' + totalSec + 's');
return [{ json: {
  job_id:           data.job_id,
  title:            data.title,
  philosopher:      data.philosopher,
  quote:            data.quote,
  caption:          data.caption,
  hashtags:         data.hashtags,
  drive_video_url:  data.drive_video_url || null,
  final_video_path: data.final_video_path,
  output_filename:  data.output_filename,
  drive_file_id:    data.drive_file_id  || null,
  thumb_url:        data.thumb_url || null,
  sheet_row:        data.sheet_row,
  total_time_sec:   totalSec,
  status:           'stage2_complete'
}}];

const fs = require('fs');
const data = $('Assemble Video').first().json;
const thumbPath = data.thumb_path;
if (!thumbPath || !fs.existsSync(thumbPath)) {
  console.log('No thumb file at', thumbPath, '- skipping');
  return [{ json: { ...data, thumb_skipped: true } }];
}
const stat = fs.statSync(thumbPath);
const buf = fs.readFileSync(thumbPath);
const b64 = buf.toString('base64');
return [{
  json: { ...data, thumb_skipped: false },
  binary: { data: { data: b64, mimeType: 'image/jpeg', fileName: data.thumb_filename, fileExtension: 'jpg' } }
}];
